const TaskList = mirror({
  tag: 'List',
  base: {
    direction: 'vertical',
    gap: '$md.gap',
    background: '$surface.bg',
    padding: '$md.pad'
  }
})

const TaskItem = mirror({
  tag: 'Item',
  base: {
    direction: 'horizontal',
    justifyContent: 'between',
    alignItems: 'center',
    padding: '$sm.pad',
    background: '$elevated.bg',
    borderRadius: '$sm.rad',
    listItem: true
  },
  states: {
    hover: { background: '$hover.bg' }
  }
})

const App = () => (
  <TaskList>
    {each('$task', '$tasks', (
      <TaskItem>
        <Row style={{ gap: '$sm.gap', alignItems: 'center' }}>
          <Checkbox 
            checked='{$task.completed}'
            onClick={{ 
              action: 'change', 
              target: '$task', 
              property: 'completed' 
            }} 
          />
          <Text style={{ 
            color: '$task.completed ? $muted.col : $default.col',
            textDecoration: '$task.completed ? "line-through" : "none"'
          }}>
            {'{$task.title}'}
          </Text>
        </Row>
        <Button 
          onClick={{ 
            action: 'delete', 
            target: '$task' 
          }}
        >
          <Icon name="trash" />
        </Button>
      </TaskItem>
    ))}
  </TaskList>
)
